"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import {
  ArrowLeft,
  Package,
  User,
  Image as ImageIcon,
  Calendar,
  Info,
} from "lucide-react";

const BASE_URL = "http://localhost:5000";

const ItemDetailsPage = () => {
  const { id } = useParams();
  const router = useRouter();

  const [item, setItem] = useState(null);
  const [loading, setLoading] = useState(true);

  // ================= FETCH ITEM DETAILS =================
  useEffect(() => {
    if (!id) return;

    const fetchItem = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch(`${BASE_URL}/item/details/${id}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) throw new Error("Failed to fetch item details");
        const data = await res.json();
        setItem(data);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchItem();
  }, [id]);

  if (loading)
    return (
      <div className="flex items-center justify-center min-h-screen text-gray-500 animate-pulse">
        Loading item details...
      </div>
    );

  if (!item)
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <p className="text-xl font-semibold text-gray-600">Item not found</p>
        <button
          onClick={() => router.back()}
          className="mt-4 text-blue-600 hover:underline"
        >
          Go back
        </button>
      </div>
    );

  const {
    itemName,
    category,
    location,
    type,
    status,
    isVerified,
    description,
    photos,
    postedBy,
    createdAt,
    updatedAt,
  } = item;

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Header Navigation */}
      <div className="bg-white border-b sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
          <button
            onClick={() => router.back()}
            className="flex items-center text-gray-600 hover:text-gray-900 transition"
          >
            <ArrowLeft size={20} className="mr-2" /> Back to Items
          </button>
          <span
            className={`px-3 py-1 rounded-full text-xs font-bold uppercase ${
              status === "pending"
                ? "bg-yellow-100 text-yellow-700"
                : status === "approved"
                  ? "bg-green-100 text-green-700"
                  : "bg-red-100 text-red-700"
            }`}
          >
            Status: {status}
          </span>
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-6 mt-4">
        <h1 className="text-2xl font-bold text-gray-800 mb-8">{itemName}</h1>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Left Column: Item Info */}
          <div className="lg:col-span-2 space-y-6">
            {/* Item Details Section */}
            <section className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
              <div className="p-6">
                <div className="flex items-center mb-4 text-blue-600">
                  <Package size={22} className="mr-2" />
                  <h2 className="text-lg font-bold">Item Information</h2>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Photo Gallery */}
                  {photos && photos.length > 0 && (
                    <div className="space-y-3">
                      <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">
                        Item Photos
                      </p>
                      <div className="grid grid-cols-2 gap-2">
                        {photos.map((img, i) => (
                          <img
                            key={i}
                            src={
                              img.startsWith("http") ? img : `${BASE_URL}${img}`
                            }
                            alt={itemName}
                            className="aspect-square w-full object-cover rounded-lg border bg-gray-50"
                          />
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Attributes */}
                  <div className="space-y-4">
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Category
                      </label>
                      <p className="text-gray-800 font-medium">{category}</p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Type
                      </label>
                      <p className="text-gray-800 font-medium capitalize">
                        {type}
                      </p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Verified
                      </label>
                      <p
                        className={
                          isVerified
                            ? "text-green-600 font-bold"
                            : "text-gray-500"
                        }
                      >
                        {isVerified ? "✓ Yes" : "No"}
                      </p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Location
                      </label>
                      <p className="text-gray-700">{location}</p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Description
                      </label>
                      <p className="text-gray-600 text-sm leading-relaxed">
                        {description}
                      </p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Created At
                      </label>
                      <p className="text-gray-600 text-sm">
                        {new Date(createdAt).toLocaleString()}
                      </p>
                    </div>
                    <div>
                      <label className="text-xs text-gray-400 font-bold uppercase">
                        Last Updated
                      </label>
                      <p className="text-gray-600 text-sm">
                        {new Date(updatedAt).toLocaleString()}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>

          {/* Right Column: Posted By */}
          <div className="space-y-6">
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
              <div className="flex items-center mb-6 text-gray-800">
                <User size={22} className="mr-2 text-green-600" />
                <h2 className="text-lg font-bold">Posted By</h2>
              </div>
              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-green-100 text-green-700 flex items-center justify-center font-bold">
                    {postedBy?.name?.charAt(0)}
                  </div>
                  <div>
                    <p className="font-bold text-gray-800">{postedBy?.name}</p>
                    <p className="text-xs text-gray-500">{postedBy?.email}</p>
                  </div>
                </div>
                <hr className="border-gray-50" />
                <div className="flex items-center gap-2 text-gray-500 text-sm mt-2">
                  <Calendar size={16} />{" "}
                  <span>{new Date(createdAt).toLocaleDateString()}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default ItemDetailsPage;
